+fn convert_usage(usage: &BedrockUsage) -> Usage {
+    let total = if usage.total_tokens > 0 {
+        usage.total_tokens
+    } else {
+        usage.input_tokens + usage.output_tokens
+    };
+
+    Usage {
+        input: usage.input_tokens,
+        output: usage.output_tokens,
+        total_tokens: total,
+        ..Usage::default()
+    }
+}
